queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?facilitytype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFacilities ?child ; p:hasBank_Branch ?parent . } GROUP BY ?child }
  ?child p:FacilityType ?facilitytype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Branches } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?facilitytype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFacilities ?child ; p:hasBank_Branch ?parent . } GROUP BY ?child }
  ?child p:FacilityType ?facilitytype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Branches } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?branchname ?facilitytype WHERE {
  ?bank_branch_facilities a :Bank_Branch_Facilities .
  ?facilities a :Facilities .
  ?bank_branch_facilities p:hasFacilities ?facilities .
  ?bank_branch a :Branches .
  ?bank_branch_facilities p:hasBank_Branch ?bank_branch .
  ?bank_branch p:BranchName ?branchname .
  ?facilities p:FacilityType ?facilitytype .
} }
}
